const upsertSystemSetting = `-- name: UpsertSystemSetting :exec
INSERT INTO system_settings (key, value, value_type, category, description, is_sensitive, updated_at)
VALUES ($1, $2, $3, $4, $5, $6, now())
ON CONFLICT(key) DO UPDATE SET
    value = excluded.value,
    value_type = excluded.value_type,
    description = excluded.description,
    is_sensitive = excluded.is_sensitive,
    updated_at = now()
`

type UpsertSystemSettingParams struct {
	Key         string      `json:"key"`
	Value       string      `json:"value"`
	ValueType   string      `json:"value_type"`
	Category    string      `json:"category"`
	Description pgtype.Text `json:"description"`
	IsSensitive bool        `json:"is_sensitive"`
}

func (q *Queries) UpsertSystemSetting(ctx context.Context, arg UpsertSystemSettingParams) error {
	_, err := q.db.Exec(ctx, upsertSystemSetting,
		arg.Key,
		arg.Value,
		arg.ValueType,
		arg.Category,
		arg.Description,
		arg.IsSensitive,
	)
	return err
}

const upsertUserPreferences = `-- name: UpsertUserPreferences :exec
INSERT INTO user_preferences (user_id, preferences_json, created_at, updated_at)
VALUES ($1, $2, now(), now())
ON CONFLICT(user_id) DO UPDATE SET
    preferences_json = excluded.preferences_json,
    updated_at = now()
`

type UpsertUserPreferencesParams struct {
	UserID          int64  `json:"user_id"`
	PreferencesJson string `json:"preferences_json"`
}

// Insert or update user preferences
func (q *Queries) UpsertUserPreferences(ctx context.Context, arg UpsertUserPreferencesParams) error {
	_, err := q.db.Exec(ctx, upsertUserPreferences, arg.UserID, arg.PreferencesJson)
	return err
}

const userHasSourceAccess = `-- name: UserHasSourceAccess :one
SELECT EXISTS(
    SELECT 1 FROM team_members tm
    JOIN team_sources ts ON tm.team_id = ts.team_id
    WHERE tm.user_id = $1 AND ts.source_id = $2
)
`

type UserHasSourceAccessParams struct {
	UserID   int64 `json:"user_id"`
	SourceID int64 `json:"source_id"`
}

// Check if a user has access to a source through any team
func (q *Queries) UserHasSourceAccess(ctx context.Context, arg UserHasSourceAccessParams) (bool, error) {
	row := q.db.QueryRow(ctx, userHasSourceAccess, arg.UserID, arg.SourceID)
	var exists bool
	err := row.Scan(&exists)
	return exists, err
}
